<div class="page-header"><div><h2 class="page-title">Modifier la relation post / tag</h2><p class="page-meta">Mettez a jour le lien entre article et tag.</p></div></div><form action="/admin/post-tags/update"class="card form-card"method="post"><input name="old_post_id"type="hidden"value="<?=(int)$relation['post_id']?>"> <input name="old_tag_id"type="hidden"value="<?=(int)$relation['tag_id']?>"><div class="form-field"><label for="post_id">Article</label> <select class="form-select"id="post_id"name="post_id"required><?php foreach($posts as $post): ?><option value="<?=(int)$post['id']?>"<?=(int)$post['id']===(int)$relation['post_id']?'selected':''?>>#<?=(int)$post['id']?>-<?=htmlspecialchars($post['title'])?></option><?php endforeach; ?></select></div><div class="form-field"><label for="tag_id">Tag</label> <select class="form-select"id="tag_id"name="tag_id"required><?php foreach($tags as $tag): ?><option value="<?=(int)$tag['id']?>"<?=(int)$tag['id']===(int)$relation['tag_id']?'selected':''?>>#<?=(int)$tag['id']?>-<?=htmlspecialchars($tag['name'])?></option><?php endforeach; ?></select></div><button class="btn btn-primary"type="submit">Mettre a jour</button> <a class="btn btn-ghost"href="/admin/post-tags">Annuler</a></form>